const items = $input.all();
const results = [];

for (const item of items) {
  const input = { ...(item.json || {}) };
  const technicalReadme = String(
    input.technicalReadme ||
    input.output ||
    input.text ||
    input.response ||
    ''
  ).trim();

  if (!technicalReadme) {
    throw new Error('Missing technicalReadme/output/text/response to save as Markdown file.');
  }

  const releaseVersion = String(
    input.releaseVersion ||
    input.release?.currentVersion ||
    input.raw?.release?.currentVersion ||
    input.raw?.raw?.release?.currentVersion ||
    'unknown'
  ).trim();

  const baseDir = String(
    input.outputDir ||
    'C:/Users/mateo-soto/Desktop/proyectos/JsatReadme'
  ).trim().replace(/\\/g, '/').replace(/\/$/, '');

  const readmeFileName = String(
    input.readmeFileName ||
    `README-release-${releaseVersion}.md`
  ).trim().replace(/[<>:"/\\|?*]+/g, '-');

  const htmlFileName = readmeFileName.replace(/\.md$/i, '') + '.html';

  const mdOutputPath = `${baseDir}/${readmeFileName}`;
  const htmlOutputPath = `${baseDir}/${htmlFileName}`;

  const htmlContent = `<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="utf-8">\n  <title>Release Report ${releaseVersion}</title>\n  <script src="https://cdn.jsdelivr.net/npm/marked/marked.min.js"></script>\n  <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/github-markdown-css/5.5.0/github-markdown.min.css">\n  <style>\n    body { box-sizing: border-box; min-width: 200px; max-width: 980px; margin: 0 auto; padding: 45px; }\n    @media (max-width: 767px) { body { padding: 15px; } }\n  </style>\n</head>\n<body class="markdown-body">\n  <div id="content"></div>\n  <script>\n    const markdown = decodeURIComponent("${encodeURIComponent(technicalReadme)}");\n    document.getElementById('content').innerHTML = marked.parse(markdown);\n  </script>\n</body>\n</html>`;

  results.push({
    json: {
      ...input,
      kind: 'savedReadmeRequest',
      releaseVersion,
      readmeFileName,
      outputDir: baseDir,
      outputPath: mdOutputPath,
      technicalReadme,
    },
    binary: {
      data: {
        data: Buffer.from(technicalReadme, 'utf8').toString('base64'),
        mimeType: 'text/markdown',
        fileName: readmeFileName,
        fileExtension: 'md',
      },
    },
  });

  results.push({
    json: {
      ...input,
      kind: 'savedReadmeRequestHtml',
      releaseVersion,
      readmeFileName: htmlFileName,
      outputDir: baseDir,
      outputPath: htmlOutputPath,
      technicalReadme,
    },
    binary: {
      data: {
        data: Buffer.from(htmlContent, 'utf8').toString('base64'),
        mimeType: 'text/html',
        fileName: htmlFileName,
        fileExtension: 'html',
      },
    },
  });
}

return results;

return {
  json: {
    kind: 'savedReadmeResult',
    status: 'saved',
    outputPath: $json.outputPath,
    readmeFileName: $json.readmeFileName,
    releaseVersion: $json.releaseVersion,
    technicalReadme: $json.technicalReadme,
  },
};
